solution_code:
#include <iostream>

int computeArea(int length, int width) {
    return length * width;
}

int computePerimeter(int length, int width) {
    return 2 * (length + width);
}

void printStats(int area, int perimeter, int halfPerimeter) {
    std::cout << "Area: " << area << '\n';
    std::cout << "Perimeter: " << perimeter << '\n';
    std::cout << "Half-perimeter: " << halfPerimeter << '\n';
}

int main() {
    int length{}, width{};
    std::cin >> length >> width;

    int area { computeArea(length, width) };
    int perimeter { computePerimeter(length, width) };
    int halfPerimeter { perimeter / 2 };
    printStats(area, perimeter, halfPerimeter);

    return 0;
}

