solution_code:
#include <iostream>

int square(int x) {
    return x * x;
}

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    std::cout << "Square of a: " << square(a) << '\n';
    std::cout << "Square of b: " << square(b) << '\n';
    std::cout << "Sum of squares: " << (square(a) + square(b)) << '\n';
    std::cout << "Square of sum: " << square(a + b) << '\n';

    return 0;
}
